from flask import Flask, request
from prometheus_client import Counter, Gauge, Histogram, start_http_server
import logging

app = Flask(__name__)

# Prometheus metrics
REQUEST_COUNTER = Counter('requests_total', 'Total number of requests')
SUCCESSFUL_REQUESTS = Counter('successful_requests_total', 'Successful requests total')
UNAUTHORIZED_REQUESTS = Counter('unauthorized_requests_total', 'Unauthorized requests total')
ERROR_REQUESTS = Counter('error_requests_total', 'Error requests total')

USER_ID_HISTOGRAM = Histogram('user_id_histogram', 'Histogram of user IDs')
API_KEY_HISTOGRAM = Histogram('api_key_histogram', 'Histogram of API keys')
REQUEST_BODY_SIZE_HISTOGRAM = Histogram('request_body_size_histogram', 'Histogram of request body sizes')

@app.route('/metrics')
def metrics():
    return prometheus_client.generate_latest()

@app.before_request
def log_request_data():
    USER_ID_HISTOGRAM.observe(request.json.get('user_id') or None)
    API_KEY_HISTOGRAM.observe(request.headers.get('X-API-KEY'))
    REQUEST_BODY_SIZE_HISTOGRAM.observe(len(request.get_json()))

@app.after_request
def log_response_data(response):
    if request.method == 'POST':
        SUCCESSFUL_REQUESTS.inc()

    if response.status_code >= 400:
        ERROR_REQUESTS.inc()
    elif response.status_code == 401:
        UNAUTHORIZED_REQUESTS.inc()

    REQUEST_COUNTER.inc()

if __name__ == '__main__':
    start_http_server(8000)
    app.run(debug=True)